// 1. Берём json из ноды "Updata Jira-Status"
const src = $node["Updata Jira-Status"].json;

// Это ровно то же самое, что твои выражения в Set:
// workerId  - {{ $('Updata Jira-Status').item.json.desktop }}
// prompt    - {{ $('Updata Jira-Status').item.json.prompt }}
// ticket    - {{ $('Updata Jira-Status').item.json.issue }}
// status    - {{ $('Updata Jira-Status').item.json.status }}
const workerId = src.desktop;
const prompt   = src.prompt;
const ticket   = src.issue;
const status   = src.status;

// 2. Берём все data_* из текущего item
// (там, где раньше в debugJson ты видел поле data)
const item = $json;
const data = item.data || {};

// 3. Формируем итоговый объект с нужными полями
const result = {
  workerId,  // = desktop
  prompt,    // = prompt
  ticket,    // = issue
  status,    // = status
};

// 4. Разворачиваем data_0, data_1, data_2, ... в корень
Object.keys(data).forEach((key) => {
  // key уже вида "data_0", "data_1", ...
  result[key] = data[key];
});

// 5. Отдаём один item в нужном формате
return {
  json: result,
};

const items = $input.all();
const fileNames = [];

for (const item of items) {
  const attachments = item.json.fields?.attachment || [];

  for (const att of attachments) {
    const content = att.content || '';

    if (typeof content !== 'string') continue;

    const lowerContent = content.toLowerCase();

    // Ищем readme или content
    if (!lowerContent.includes('readme') && !lowerContent.includes('content')) {
      continue;
    }

    let fileName =
      att.fileName ||
      att.filename ||
      att.name ||
      '';

    // Если имени нет — вытаскиваем из URL/строки
    if (!fileName) {
      const clean = content.split('?')[0].split('#')[0];
      fileName = clean.split('/').pop() || '';
    }

    if (!fileName) fileName = 'unknown';

    fileNames.push(fileName);
  }
}

// Один item на выходе
return [
  {
    json: {
      fileNames, // массив всех найденных имён
      count: fileNames.length,
    }
  }
];

// Берём текст из AI Agent
const aiOutput = $input.first().json.output || $input.first().json.text || $input.first().json.content;

// Формируем Markdown
const mdContent = `# AI Response\n\n${aiOutput}`;

const buffer = Buffer.from(mdContent, 'utf8');

return [{
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'text/markdown',
      fileName: 'prompt_dropbox.md',   // <-- нужное имя
    }
  },
  json: {
    source: 'AI Agent',
    format: 'markdown',
  }
}];

const item = $json;

const attachments = item.fields?.attachment || [];
const attachmentIds = attachments.map(a => a.id);

// Возвращаем только список ID в json
return {
  json: {
    attachmentIds,
  },
};

const item = $json;

// attachments — массив объектов вложений
const attachments = item.fields?.attachment || [];

// 1) Сначала фильтруем по имени/ссылке:
//    - выкидываем всё, где есть "dropbox"
//    - оставляем только то, где есть "promt"
const filtered = attachments.filter(a => {
  const text = (a.filename || a.content || '').toLowerCase();

  // если есть dropbox — выкидываем
  if (text.includes('dropbox')) return false;

  // оставляем только promt (если нужно prompt — добавь вторую проверку)
  return text.includes('prompt') || text.includes('promt');
;
});

// 2) Мапим в массив ID
const attachmentIds = filtered.map(a => a.id);

return {
  json: {
    attachmentIds, // ID только тех файлов, где в имени/ссылке есть promt и нет dropbox
  },
};

