const result = [];

for (const item of items) {
  const attachments = item.json.fields?.attachment || [];

  // 1) сначала ищем dropbox‑файл
  let chosen = attachments.find(att => {
    const content = att.content || '';
    return typeof content === 'string' && content.toLowerCase().includes('dropbox');
  });

  // 2) если dropbox не найден — берём любой первый файл, если он есть
  if (!chosen && attachments.length > 0) {
    chosen = attachments[0];
  }

  // 3) если вообще нет вложений — ничего не добавляем
  if (chosen) {
    const content = chosen.content || '';
    result.push({
      json: {
        content,
        attachment: chosen,
        sourceKey: 'fields.attachment.content',
      },
    });
  }
}

return result;

